<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Responsive Breadcrumbs</title>
    <link rel="stylesheet" href="styles.css">
</head>
<body>
    <nav class="bg-gray-800 text-gray-100 p-4 mb-8">
        <ul class="max-w-3xl mx-auto flex justify-between items-center">
            <li class="text-lg font-bold"><a href="#">Home</a></li>
            <li class="px-4 text-lg font-bold"><a href="#">About</a></li>
            <li class="px-4 text-lg font-bold"><a href="#">Contact</a></li>
        </ul>
    </nav>
    <div class="max-w-6xl mx-auto p-4 bg-gray-100">
        <h1 class="text-3xl font-bold mb-4">Responsive Breadcrumbs</h1>
        <ol class="flex items-center space-x-4">
            <li class="text-lg font-bold"><a href="#">Home</a></li>
            <li class="px-4 text-lg font-bold"><a href="#">About</a></li>
            <li class="px-4 text-lg font-bold"><a href="#">Contact</a></li>
            <li class="text-lg font-bold">Current Page</li>
        </ol>
    </div>
</body>
</html>
css: * {
    box-sizing: border-box;
}
body {
    margin: 0;
    padding: 0;
    font-family: Arial, sans-serif;
}
nav {
    background-color: #333;
    color: #fff;
    padding: 1rem;
}
nav ul {
    list-style: none;
    margin: 0;
    padding: 0;
}
nav li {
    display: inline-block;
    margin-right: 20px;
}
av a {
    color: #fff;
    text-decoration: none;
}
av a:hover {
    color: #ccc;
}
.max-w-3xl {
    max-width: 800px;
    margin: 0 auto;
}
.max-w-6xl {
    max-width: 1200px;
    margin: 0 auto;
}
.bg-gray-100 {
    background-color: #f7f7f7;
}
h1 {
    font-size: 3rem;
}
ol {
    list-style: none;
    padding: 0;
    margin: 0;
}
ol li {
    display: block;
    padding: 0.5rem;
}
ol li a {
    color: #333;
    text-decoration: none;
}
ol li a:hover {
    color: #666;
}
mobile-nav {
    display: none;
}
@media (max-width: 768px) {
    .mobile-nav {
        display: block;
    }
    .nav-links {
        display: none;
    }
}
